import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface ICommandInfo {
    command: string;
    parameters: string;
    description: string;
}

export class CommandsListParser implements IMessageParser {
    private _commands: ICommandInfo[] = [];

    public flush(): boolean {
        this._commands = [];
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        this._commands = [];

        const count = wrapper.readInt();

        for (let i = 0; i < count; i++) {
            const command = wrapper.readString();
            const parameters = wrapper.readString();
            const description = wrapper.readString();

            this._commands.push({
                command,
                parameters,
                description,
            });
        }

        return true;
    }

    public get commands(): ICommandInfo[] {
        return this._commands;
    }
}
